  ('elementary-0489de64-moex-00345', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '低成本航空公司（LCC）為乘客提供一種經濟有效的飛行選擇。下列那項描述能準確地反映LCC之 核心特點？', '["低成本航空通常減少附加服務，如免費行李托運和餐飲，以降低運營成本並提供更低的機票價格", "低成本航空公司只在非繁忙的時間運營，如深夜或清晨，以減少機場使用費用", "低成本航空公司提供全包式服務，包括免費餐飲、娛樂系統和行李托運", "所有低成本航空公司都不提供國際航線，僅限於國內短程航班"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00346', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列那一個車站為高鐵與臺鐵共構的車站？', '["高鐵臺中站", "高鐵左營站", "松山車站", "南港車站"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
