  ('elementary-0489de64-moex-00348', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '汽車貨運業通常都有購買車輛、租用場站等短期內無法變動之固定成本，假設運送貨物之每單位重 量距離（例如每延噸公里）變動成本為一常數，其每單位重量距離之平均總成本隨距離增加而改變之 方向為何？', '["上升", "下降", "持平", "不一定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
